SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpb_faifa_vh_get_desc (as_vourcher_no CHAR , as_type char ) RETURNS char AS $body$
DECLARE

ls_vh_desc sc_acc_m_account_master.account_name%type;

BEGIN
    SELECT sc_acc_m_account_master.account_name
    INTO STRICT ls_vh_desc
    FROM sc_fin_vourcher_detail,   
        sc_acc_m_account_master  
    WHERE ( sc_fin_vourcher_detail.account_id = sc_acc_m_account_master.account_id )   
    and (sc_fin_vourcher_detail.account_id IS NOT NULL AND sc_fin_vourcher_detail.account_id::text <> '')    
    and     sc_fin_vourcher_detail.seq_no =  (  SELECT min( seq_no )
                                                from sc_fin_vourcher_detail
                                                where (account_id IS NOT NULL AND account_id::text <> '') 
                                                and (	vourcher_no =  as_vourcher_no ) 
                                              )  
    and   sc_fin_vourcher_detail.vourcher_no =  as_vourcher_no;

    case trim(both upper( as_type ))
    when 'OTH' then
      --ค่าใช้จ่ายของ Vouucher ใบนี้
      ls_vh_desc := ls_vh_desc;
    else
      ls_vh_desc := ' ';
    end case;

    
    return ls_vh_desc;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
